def transition(state, action):
    s = dict(state)
    name = action["name"]
    params = action.get("params") or {}
    status = s["status"]

    if name == "request":
        # Open a fresh change request only when nothing is in flight: at start,
        # or after the previous change deployed or was rolled back.
        if status in ("idle", "deployed", "rolled_back"):
            s["status"] = "requested"
            s["approvals"] = 0
            s["risk"] = int(params.get("risk", s["risk"]))
            s["required_approvals"] = int(
                params.get("required_approvals", s["required_approvals"]))
            s["change_id"] = s["change_id"] + 1
    elif name == "approve":
        # Each CAB member casts one approval; quorum promotes the change.
        if status == "requested":
            s["approvals"] = s["approvals"] + 1
            if s["approvals"] >= s["required_approvals"]:
                s["status"] = "approved"
    elif name == "deploy":
        # Production is gated on approval: only an 'approved' change may ship.
        if status == "approved":
            s["status"] = "deployed"
            s["deployments"] = s["deployments"] + 1
    elif name == "rollback":
        # Revert a live deployment; the change closes as 'rolled_back'.
        if status == "deployed":
            s["status"] = "rolled_back"
            s["rollbacks"] = s["rollbacks"] + 1
    return s

