def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            k = k.strip().lower().replace(' ', '_')
            v = v.strip()
            if k in ('risk', 'required_approvals') and v.lstrip('-').isdigit():
                out[k] = int(v)
    return out
